10	 *
11	 * Cells are represented as strings in the format "x,y" where x and y are integers.
12	 *
13	 * Rules applied:
14	 * - Cell with < 2 neighbors dies (underpopulation)
15	 * - Cell with 2-3 neighbors survives
16	 * - Cell with > 3 neighbors dies (overpopulation)
17	 * - Dead cell with exactly 3 neighbors becomes alive (reproduction)
18	 *
19	 * @param cells Set of living cells as coordinate strings "x,y"
20	 * @returns Set of living cells in the next generation
21	 */
22	export function nextGeneration(cells: Set<string>): Set<string> {
23	  if (cells.size === 0) {
24	    return new Set();
25	  }
26	
27	  const cellsToCheck = new Set<string>();
28	  const neighbors = [
29	    [-1, -1], [-1, 0], [-1, 1],
30	    [0, -1],           [0, 1],
31	    [1, -1],  [1, 0],  [1, 1]
32	  ];
33	
34	  // Add all living cells and their neighbors to check
35	  for (const cell of cells) {
36	    const [x, y] = parseCoordinate(cell);
37	    cellsToCheck.add(cell);
38	    for (const [dx, dy] of neighbors) {
39	      cellsToCheck.add(`${x + dx},${y + dy}`);
40	    }
41	  }
42	
43	  const nextGen = new Set<string>();
44	
45	  // Check each cell and determine if it survives or is born
46	  for (const cell of cellsToCheck) {
47	    const [x, y] = parseCoordinate(cell);
48	    let liveNeighborCount = 0;
49	
50	    for (const [dx, dy] of neighbors) {
51	      if (cells.has(`${x + dx},${y + dy}`)) {
52	        liveNeighborCount++;
53	      }
54	    }
55	
56	    const isAlive = cells.has(cell);
57	
58	    // Apply Game of Life rules
59	    if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
60	      nextGen.add(cell);
61	    } else if (!isAlive && liveNeighborCount === 3) {
62	      nextGen.add(cell);
63	    }
64	  }
